import{_ as o,o as r,c as t,a2 as d}from"./chunks/framework.C90q7Ucc.js";const m=JSON.parse('{"title":"数据、可观测性与验证","description":"","frontmatter":{},"headers":[],"relativePath":"product/data-observability.md","filePath":"product/data-observability.md","lastUpdated":1781278400000}'),c={name:"product/data-observability.md"};function a(s,e,i,n,l,h){return r(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="数据、可观测性与验证" tabindex="-1">数据、可观测性与验证 <a class="header-anchor" href="#数据、可观测性与验证" aria-label="Permalink to &quot;数据、可观测性与验证&quot;">​</a></h1><h2 id="本地数据" tabindex="-1">本地数据 <a class="header-anchor" href="#本地数据" aria-label="Permalink to &quot;本地数据&quot;">​</a></h2><p>默认数据目录是 <code>~/.codelark</code>。</p><table tabindex="0"><thead><tr><th>文件</th><th>用途</th><th>代码入口</th></tr></thead><tbody><tr><td><code>config.toml</code></td><td>全局主配置，使用 v2 TOML shape</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/configuration/service.ts" target="_blank" rel="noreferrer">src/configuration/service.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/configuration/schema.ts" target="_blank" rel="noreferrer">src/configuration/schema.ts</a></td></tr><tr><td><code>config/sessions/&lt;session-id&gt;.toml</code></td><td>Session 级持久化覆盖，例如 cwd、模型、provider、sandbox、reasoning、tmux 显式绑定</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/configuration/service.ts" target="_blank" rel="noreferrer">src/configuration/service.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/domain/session-runtime.ts" target="_blank" rel="noreferrer">src/domain/session-runtime.ts</a></td></tr><tr><td><code>config/channels/&lt;channel-id&gt;.toml</code></td><td>Channel 级持久化覆盖，复用同一套 TOML shape</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/configuration/service.ts" target="_blank" rel="noreferrer">src/configuration/service.ts</a></td></tr><tr><td><code>config.json</code> / <code>config.env</code></td><td>v1 迁移输入；迁移成功后归档为 <code>.migrated-v1*</code>，不再作为运行时配置来源</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/configuration/migrations/v1.ts" target="_blank" rel="noreferrer">src/configuration/migrations/v1.ts</a></td></tr><tr><td><code>data/sessions.json</code></td><td>BridgeSession</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/storage/json-store.ts" target="_blank" rel="noreferrer">src/storage/json-store.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/schemas/data/sessions.v1.schema.json" target="_blank" rel="noreferrer">schemas/data/sessions.v1.schema.json</a></td></tr><tr><td><code>data/channel-chats.json</code></td><td>ChannelChat 绑定</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/storage/json-store.ts" target="_blank" rel="noreferrer">src/storage/json-store.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/schemas/data/channel-chats.v1.schema.json" target="_blank" rel="noreferrer">schemas/data/channel-chats.v1.schema.json</a></td></tr><tr><td><code>data/messages/&lt;sessionId&gt;.json</code></td><td>Bridge 消息缓存</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/storage/json-store.ts" target="_blank" rel="noreferrer">src/storage/json-store.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/schemas/data/messages.v1.schema.json" target="_blank" rel="noreferrer">schemas/data/messages.v1.schema.json</a></td></tr><tr><td><code>data/audit.jsonl</code></td><td>审计日志，当前新记录按 JSONL 追加；旧 <code>data/audit.json</code> 仍会被读取</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/storage/json-store.ts" target="_blank" rel="noreferrer">src/storage/json-store.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/schemas/data/audit.v1.schema.json" target="_blank" rel="noreferrer">schemas/data/audit.v1.schema.json</a></td></tr><tr><td><code>runtime/status.json</code></td><td>Bridge 运行状态</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/entrypoints/daemon.ts" target="_blank" rel="noreferrer">src/entrypoints/daemon.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/local-service/manager.ts" target="_blank" rel="noreferrer">src/local-service/manager.ts</a></td></tr><tr><td><code>runtime/ui-server.json</code></td><td>UI 运行状态</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/operator-ui/server.ts" target="_blank" rel="noreferrer">src/operator-ui/server.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/local-service/manager.ts" target="_blank" rel="noreferrer">src/local-service/manager.ts</a></td></tr></tbody></table><p>Codex 自有数据仍在 <code>~/.codex</code>；CodeLark 只读索引和镜像。Claude Code 自有 JSONL 也由 Claude Code 生成；bridge 只保存可继续定位它的 runtime 身份。</p><h2 id="可观测性" tabindex="-1">可观测性 <a class="header-anchor" href="#可观测性" aria-label="Permalink to &quot;可观测性&quot;">​</a></h2><p>CodeLark 的可观测性来自四层：</p><ul><li>IM 内状态命令：<code>/status</code>、<code>/check</code>、<code>/his</code>、<code>/doctor</code>。</li><li>本地日志：<code>~/.codelark/logs/bridge.log</code>、hot update log。<code>bridge.log</code> 是结构化 JSONL；常用字段包括 <code>time</code>、<code>level</code>、<code>msg</code>、<code>name</code>、<code>event</code>、<code>duration_ms</code>、<code>lane</code>、<code>channel</code>、<code>chat</code>、<code>category</code>。</li><li>本地 JSON/JSONL 数据：sessions、channel-chats、messages、audit。</li><li>真实 E2E 报告：real Feishu harness 输出的成功或失败 JSON report。</li></ul><p>关键性能事件：</p><ul><li><code>perf.feishu.request</code>：飞书 API 请求耗时，常用字段包括 <code>target</code>、<code>operation</code>、<code>status</code>、<code>duration_ms</code>、<code>chat</code>、<code>message_id</code>、<code>stream_key</code>。</li><li><code>perf.delivery.send</code>：delivery pipeline 发送耗时，常用字段包括 <code>channel</code>、<code>chat</code>、<code>status</code>、<code>duration_ms</code>、<code>kind</code>。</li><li><code>perf.card.sync_plan</code>：CardKit streaming card 同步计划，常用字段包括 <code>stream_key</code>、<code>operation</code>、<code>reason</code>、<code>full_refresh_reason</code>、<code>action_count</code>、<code>shadow_trust</code>。</li><li><code>perf.card.full_refresh_payload</code>：整卡刷新 payload 规模，常用字段包括 <code>stream_key</code>、<code>component_count</code>、<code>payload_bytes</code>、<code>markdownCount</code>、<code>buttonCount</code>。</li><li><code>perf.card.lifecycle</code>：单张流式卡片生命周期汇总，常用字段包括 <code>terminal_status</code>、<code>elapsed_ms</code>、<code>flush_attempts</code>、<code>flush_failures</code>、<code>full_refresh_count</code>、<code>api_top</code>。</li><li><code>perf.mirror.batch</code> / <code>perf.mirror.subscription</code>：mirror reconcile 批次和慢 subscription，常用字段包括 <code>runtime</code>、<code>duration_ms</code>、<code>concurrency</code>、<code>binding_id</code>、<code>status</code>。</li><li><code>perf.mirror.subscription_stage</code>：慢 mirror subscription 的子阶段耗时，当前覆盖 <code>route_records</code> 和 <code>deliver_turns</code>，用于区分本地 JSONL 读取与下游 runtime/飞书投递等待。</li><li><code>perf.thread_table_pin</code>：线程表置顶后台任务耗时，常用字段包括 <code>channel</code>、<code>chat</code>、<code>scope</code>、<code>status</code>、<code>duration_ms</code>、<code>message_id</code>、<code>previous_pinned_message_id</code>。</li><li><code>adapter.message.scheduled</code> / <code>adapter.message.started</code> / <code>adapter.message.finished</code>：adapter 入口生成的消息 span timeline；普通 command/callback 使用 chat job 并发执行，只在同 chat 存在 active conversation barrier 时等待；regular prompt 使用 <code>session:&lt;session_id&gt;</code> lane；<code>/runtime</code>、<code>/provider</code>、<code>/clear</code>、<code>/cd</code>、<code>/model</code>、<code>/mode</code>、<code>/sandbox</code>、<code>/network</code>、<code>/reasoning</code>、<code>/current-config</code>、session-mutating <code>/t</code> 等命令会进入 session queue 并声明 <code>conversation_barrier=true</code>，阻塞同一对话后续非 control command/job；<code>/stop</code>/permission/screen-stop 等高优先级控制消息使用 control lane；<code>/tmux-screen</code>、<code>/pty-screen</code>、<code>/shell</code> 使用 job lane，其中 screen monitor job 不等待 conversation barrier，<code>/shell</code> 等普通 job 仍等待。可直接按 <code>span_id</code>、<code>parent_span_id</code>、<code>lane</code>、<code>lane_kind</code>、<code>job_kind</code>、<code>conversation_barrier</code>、<code>message_id</code>、<code>session_id</code>、<code>started_at_ms</code>、<code>ended_at_ms</code>、<code>duration_ms</code> 聚合。</li><li><code>adapter.message.wait</code> / <code>adapter.message.handler</code>：adapter 队列等待和 handler 慢路径告警，复用同一 span 字段；排队阻塞关系写入 <code>blocked_by_span_id</code>、<code>blocked_by_message_id</code>、<code>blocked_by_session_id</code>、<code>blocked_by_category</code>、<code>blocked_by_started_at_ms</code>、<code>blocked_by_age_ms</code>。</li><li><code>session.executor.scheduled</code> / <code>session.executor.started</code> / <code>session.executor.finished</code>：BridgeSession 串行执行队列的结构化事件，常用字段包括 <code>session_id</code>、<code>job_kind</code>、<code>queued_before</code>、<code>queued_after</code>、<code>wait_ms</code>、<code>raw_wait_ms</code>、<code>run_ms</code>、<code>status</code>。</li><li><code>perf.startup.channel_chat_check</code>：启动期 ChannelChat 存活检查耗时；<code>status=deferred</code> 表示启动通知已先发，检查会继续在后台完成。</li></ul><p>设计模块：</p><ul><li>状态命令：<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/status.ts" target="_blank" rel="noreferrer">src/bridge/command/status.ts</a></li><li>诊断命令：<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/diagnostics.ts" target="_blank" rel="noreferrer">src/bridge/command/diagnostics.ts</a></li><li>健康检查：<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/health/runtime.ts" target="_blank" rel="noreferrer">src/bridge/health/runtime.ts</a></li><li>transcript source：<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/session/transcript-source.ts" target="_blank" rel="noreferrer">src/bridge/session/transcript-source.ts</a></li><li>Doctor 脚本：<a href="https://github.com/huiyeruzhou/codelark/blob/main/scripts/doctor.sh" target="_blank" rel="noreferrer">scripts/doctor.sh</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/scripts/doctor.ps1" target="_blank" rel="noreferrer">scripts/doctor.ps1</a></li></ul><h2 id="验证入口" tabindex="-1">验证入口 <a class="header-anchor" href="#验证入口" aria-label="Permalink to &quot;验证入口&quot;">​</a></h2><ul><li>普通单元/集成测试：<a href="https://github.com/huiyeruzhou/codelark/blob/main/scripts/run-tests.js" target="_blank" rel="noreferrer">scripts/run-tests.js</a></li><li>类型检查：<code>npm run typecheck</code></li><li>真实飞书 E2E harness：<a href="https://github.com/huiyeruzhou/codelark/blob/main/scripts/real-feishu-e2e.ts" target="_blank" rel="noreferrer">scripts/real-feishu-e2e.ts</a></li><li>覆盖审计文档：<a href="./../testing/coverage-audit">docs/testing/coverage-audit.md</a></li><li>真实飞书 E2E：<a href="./../testing/real-feishu/">docs/testing/real-feishu/index.md</a></li></ul><p>真实飞书 E2E 的目标不是替代所有单元测试，而是证明关键用户场景确实能经过飞书客户端、真实 bridge、真实 runtime provider 和真实回复链路。</p>',15)])])}const b=o(c,[["render",a]]);export{m as __pageData,b as default};
